#version 330 core

// ===========================================================================
// Fragment shader para Tarea 3.
//
// Extiende el fragment shader de la tarea 2 con dos uniforms nuevos:
//
//   uniform samplerCube u_environment;
//   uniform float u_env_intensity;
//
// Si u_env_intensity > 0.0, el shader muestrea un cubemap procedural a lo
// largo del vector reflejado (R = reflect(-V, N)) para que la superficie
// "refleje" el ambiente (efecto cromado). El aporte del cubemap se mezcla
// con el resultado de Phong usando una aproximacion de Fresnel para metal.
//
// Las luces, el material y la textura 2D son identicas a la tarea 2; si
// u_env_intensity vale 0.0 el resultado es el mismo que el shader previo.
// ===========================================================================

in vec3 v_world_pos;
in vec3 v_world_normal;
in vec3 v_color;
in vec2 v_texcoord;

uniform vec3 u_light1_dir;       // direccional principal
uniform vec3 u_light1_color;
uniform float u_light1_intensity;

uniform vec3 u_light2_dir;       // direccional de color
uniform vec3 u_light2_color;
uniform float u_light2_intensity;

uniform vec3 u_light3_pos;       // puntual "emisiva" al impactar
uniform vec3 u_light3_color;
uniform float u_light3_intensity;

uniform vec3 u_ambient_color;

uniform vec3 u_mat_ambient;
uniform vec3 u_mat_diffuse;
uniform vec3 u_mat_specular;
uniform float u_mat_shininess;

uniform int u_use_texture;
uniform sampler2D u_texture;

// --- nuevos: reflexion por cubemap ---
uniform samplerCube u_environment;
uniform float u_env_intensity;

uniform vec3 u_camera_pos;

out vec4 frag_color;

vec3 phong(vec3 N, vec3 V, vec3 L, vec3 lightColor, vec3 baseColor,
           vec3 specColor, float shininess, float intensity, float attenuation) {
    float NdotL = max(dot(N, L), 0.0);
    vec3 diffuse = baseColor * lightColor * NdotL;
    vec3 R = reflect(-L, N);
    float spec = pow(max(dot(V, R), 0.0), shininess);
    vec3 specular = specColor * lightColor * spec;
    return (diffuse + specular) * intensity * attenuation;
}

void main() {
    vec3 N = normalize(v_world_normal);
    vec3 V = normalize(u_camera_pos - v_world_pos);

    vec3 baseColor = v_color;
    if (u_use_texture == 1) {
        vec3 tex = texture(u_texture, v_texcoord).rgb;
        baseColor *= tex;
    }
    vec3 diffuseColor = baseColor * u_mat_diffuse;
    vec3 ambient = u_ambient_color * u_mat_ambient * baseColor;
    vec3 result = ambient;

    vec3 L1 = normalize(u_light1_dir);
    result += phong(N, V, L1, u_light1_color, diffuseColor, u_mat_specular,
                    u_mat_shininess, u_light1_intensity, 1.0);

    vec3 L2 = normalize(u_light2_dir);
    result += phong(N, V, L2, u_light2_color, diffuseColor, u_mat_specular,
                    u_mat_shininess, u_light2_intensity, 1.0);

    if (u_light3_intensity > 0.0) {
        vec3 toL = u_light3_pos - v_world_pos;
        float dist = length(toL);
        vec3 L3 = toL / max(dist, 0.0001);
        float att = 1.0 / (1.0 + 0.25 * dist + 0.06 * dist * dist);
        result += phong(N, V, L3, u_light3_color, diffuseColor, u_mat_specular,
                        u_mat_shininess, u_light3_intensity, att);
    }

    // ------------------------------------------------------------------
    // Reflexion cromada: muestreamos el cubemap en la direccion R.
    // Usamos textureLod para tomar una version ligeramente borrosa del
    // cubemap (mipmaps generados al construir el cubemap), dando un
    // acabado cromado mas suave y menos "pixelado".
    //
    // Aplicamos una aproximacion de Fresnel-Schlick para metal, de modo
    // que la reflexion es mas fuerte en angulos rasantes y debil cuando
    // la pelota se ve "de frente".
    // ------------------------------------------------------------------
    if (u_env_intensity > 0.0) {
        vec3 R = reflect(-V, N);
        vec3 env_color = textureLod(u_environment, R, 1.5).rgb;
        float NdotV = max(dot(N, V), 0.0);
        float fresnel = 0.06 + 0.94 * pow(1.0 - NdotV, 5.0);
        // Mezclamos, manteniendo un poco del termino Phong para que el
        // Phong siga sumando brillo a las luces directas.
        result = mix(result, env_color, clamp(u_env_intensity * fresnel, 0.0, 1.0));
        // Sumamos un adicional muy pequeno del envmap "agresivo" para
        // reforzar el cromo en superficies en sombra.
        result += env_color * u_env_intensity * 0.15 * fresnel;
    }

    frag_color = vec4(result, 1.0);
}

#version 330 core

// ===========================================================================
// Shaders para el sistema de particulas de Tarea 3.
// Los vertices son puntos (GL_POINTS) — un punto por particula. Cada uno
// lleva su posicion, color y tamano (en pixeles de pantalla). Usamos
// gl_PointSize para escoger el tamano y gl_PointCoord (0..1 dentro del
// punto) para muestrear la textura circular y conseguir un sprite
// "circular" con alpha gradual.
//
// Blend aditivo (configurado desde el cliente) hace que las particulas
// se mezclen formando halos brillantes, ideal para chispas/colores.
// ===========================================================================

// ----- VERTEX SHADER -----
in vec3 position;
in vec3 color;
in float size;
in float alpha;

uniform mat4 u_view;
uniform mat4 u_projection;

out vec3 v_color;
out float v_alpha;

void main() {
    gl_Position = u_projection * u_view * vec4(position, 1.0);
    gl_PointSize = size;
    v_color = color;
    v_alpha = alpha;
}

// ----- FRAGMENT SHADER -----
uniform sampler2D u_particle_texture;
in vec3 v_color;
in float v_alpha;
out vec4 frag_color;

void main() {
    vec2 uv = gl_PointCoord;
    vec4 tex = texture(u_particle_texture, uv);
    float a = tex.a * v_alpha;
    if (a < 0.02) discard;
    vec3 col = v_color * tex.rgb;
    // Tonemapping simple para evitar que los fogonazos se saturen feo.
    col = col / (col + vec3(0.6)) * 1.6;
    frag_color = vec4(col, a);
}

#version 330 core

// ===========================================================================
// Vertex shader del sistema de particulas (Tarea 3).
//
// Cada vertice es un punto (GL_POINTS); un punto por particula. En el VS
// usamos gl_PointSize para fijar el tamano del sprite en pixeles y
// dejamos pasar al fragment shader el color y el alpha por particula.
// ===========================================================================

in vec3 position;
in vec3 color;
in float size;
in float alpha;

uniform mat4 u_view;
uniform mat4 u_projection;

out vec3 v_color;
out float v_alpha;

void main() {
    gl_Position = u_projection * u_view * vec4(position, 1.0);
    gl_PointSize = size;
    v_color = color;
    v_alpha = alpha;
}

#version 330 core

// ===========================================================================
// Fragment shader del sistema de particulas (Tarea 3).
//
// gl_PointCoord da coordenadas (0,0)-(1,1) dentro del punto. Multiplicamos
// por una textura circular con alpha gradual para producir un sprite
// "redondo" con falloff. El color final se atenua suavemente para evitar
// fogonazos saturados.
// ===========================================================================

uniform sampler2D u_particle_texture;
in vec3 v_color;
in float v_alpha;
out vec4 frag_color;

void main() {
    vec2 uv = gl_PointCoord;
    vec4 tex = texture(u_particle_texture, uv);
    float a = tex.a * v_alpha;
    if (a < 0.02) discard;
    vec3 col = v_color * tex.rgb;
    // Reinhard-like tonemapping para evitar fogonazos saturados feos.
    col = col / (col + vec3(0.6)) * 1.6;
    frag_color = vec4(col, a);
}

